from flask import Flask, request, jsonify
import json
import os
import time

app = Flask(__name__)

CACHE_DIR = "cache"
CACHE_EXPIRY = 3600  # Cache expiration in seconds

@app.route("/api/<endpoint>")
def cache_response(endpoint):
    cache_file = os.path.join(CACHE_DIR, f"{endpoint}.json")

    if os.path.exists(cache_file) and time.time() - os.path.getmtime(cache_file) < CACHE_EXPIRY:
        with open(cache_file, "r") as f:
            response = json.load(f)
    else:
        # Call the expensive API here
        response = {"data": "expensive data", "metadata": {"timestamp": time.time()}}

        with open(cache_file, "w") as f:
            json.dump(response, f)

    return jsonify(response)

if __name__ == "__main__":
    if not os.path.exists(CACHE_DIR):
        os.makedirs(CACHE_DIR)

    app.run(debug=True)